import { useContext } from "react";
import { userContext as TaskContext } from "../App";

function TaskForm ( { displayForm } ) {
    const { tasks, setTasks } = useContext(TaskContext);
    const addTask = (e) => {
        e.preventDefault();
        const title = e.target.elements.tasktitle.value;
        const description = e.target.elements.taskdescription.value;
        const priority = e.target.elements.taskpriority.value;
        const dueDate = e.target.elements.taskdueDate.value;

        if (!title || !description || !priority || !dueDate) {
            alert('Please fill in all fields');
            return;
        }

        let newId;
        if (tasks.length === 0) {
            newId = 1;
        }else {
            newId = tasks[tasks.length - 1].id + 1;
        }

        const newTask = {
            id: newId,
            title,
            description,
            completed: false,
            priority,
            dueDate
        };

        setTasks((prevTasks) => [...prevTasks, newTask]);

        e.target.reset();
    }

    return (
        <div className="form-container" style={{ display: displayForm ? "block" : "none" }}>
            <h3 className="form-title">Task Form</h3>
            <button className="" onClick={() => setDisplayForm(false)}>x</button>
            <form className="form" onSubmit={(e) => addTask(e)}>
                <div className="form-group">
                    <label htmlFor="tasktitle" className="form-label">Task title:</label>
                    <input type="text" id="tasktitle" className="form-input" />
                </div>
                <div className="form-group">
                    <label htmlFor="taskdescription" className="form-label">Task description:</label>
                    <textarea id="taskdescription" className="form-textarea" />
                </div>
                <div className="form-group">
                    <label htmlFor="taskpriority" className="form-label">Task priority:</label>
                    <select id="taskpriority" className="form-select">
                        <option value="low">Low</option>
                        <option value="medium">Medium</option>
                        <option value="high">High</option>
                    </select>
                </div>
                <div className="form-group">
                    <label htmlFor="taskdueDate" className="form-label">Due Date:</label>
                    <input type="date" id="taskdueDate" className="form-input" />
                </div>
                <button type="submit" className="btn btn-primary">Add Task</button>
            </form>
        </div>
    )
}

export default TaskForm;
